// HasRefundRequest applies the HasEdge predicate on the "refund_request" edge.
func HasRefundRequest() predicate.SubscriptionRefundAllocation {
	return predicate.SubscriptionRefundAllocation(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, RefundRequestTable, RefundRequestColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasRefundRequestWith applies the HasEdge predicate on the "refund_request" edge with a given conditions (other predicates).
